#include <stdio.h>
#include <stdlib.h>

/*
 * Binary Adder-Subtractor Implementation in C
 * Demonstrates gate-level simulation for fundamental arithmetic circuits
 */

// Basic Logic Gates
int NOT_gate(int a) {
 return 1 - a;
}

int AND_gate(int a, int b) {
 return (a == 1 && b == 1) ? 1 : 0;
}

int OR_gate(int a, int b) {
 return (a == 1 || b == 1) ? 1 : 0;
}

int XOR_gate(int a, int b) {
 return (a != b) ? 1 : 0;
}

// Half Adder: Adds two 1-bit numbers
// Returns: sum = A XOR B, carry = A AND B
void half_adder(int a, int b, int *sum, int *carry) {
 *sum = XOR_gate(a, b);
 *carry = AND_gate(a, b);
}

// Full Adder: Adds three 1-bit numbers
// Implements using two half adders + OR gate
void full_adder(int a, int b, int carry_in, int *sum, int *carry_out) {
 int sum1, carry1, sum2, carry2;

 // First half adder: A + B
 half_adder(a, b, &sum1, &carry1);

 // Second half adder: (A+B) + CarryIn
 half_adder(sum1, carry_in, &sum2, &carry2);

 // OR the carries for final carry out
 *sum = sum2;
 *carry_out = OR_gate(carry1, carry2);
}

// N-bit Ripple Carry Adder
// Adds two n-bit binary numbers using cascading full adders
void ripple_carry_adder(int *a, int *b, int n, int *result, int *final_carry) {
 int carry = 0; // Initial carry-in is 0

 for (int i = 0; i < n; i++) {
 full_adder(a[i], b[i], carry, &result[i], &carry);
 }
 *final_carry = carry;
}

// Binary to Decimal (assuming unsigned)
binary_to_decimal(int *binary, int n) {
 int decimal = 0;
 for (int i = 0; i < n; i++) {
 decimal += binary[i] * (1 << i);
 }
 return decimal;
}

// Decimal to Binary
void decimal_to_binary(int decimal, int n, int *binary) {
 if (decimal < 0) {
 // Handle negative in 2's complement
 decimal = (1 << n) + decimal;
 }
 for (int i = 0; i < n; i++) {
 binary[i] = (decimal >> i) & 1;
 }
}

// 4-bit Adder-Subtractor with Overflow Detection
// Mode = 0: Addition (A + B)
// Mode = 1: Subtraction (A - B using 2's complement)
void adder_subtractor(int *a, int *b, int n, int mode, int *result, int *overflow) {
 int carry = mode; // CarryIn = Mode (0 for add, 1 for subtract)
 int carry_into_msb = 0;

 for (int i = 0; i < n; i++) {
 // XOR gate: B XOR Mode (complements B when mode=1)
 int modified_b = XOR_gate(b[i], mode);

 // Track carry into MSB for overflow detection
 if (i == n - 1) {
 carry_into_msb = carry;
 }

 full_adder(a[i], modified_b, carry, &result[i], &carry);
 }

 int carry_out = carry;

 // Overflow detection: V = Cn XOR Cn-1 (carry_out XOR carry_into_msb)
 *overflow = XOR_gate(carry_out, carry_into_msb);
}

// Display binary array
void print_binary(int *binary, int n) {
 for (int i = n - 1; i >= 0; i--) {
 printf("%d", binary[i]);
 }
}

// Main demonstration
int main() {
 int n = 4; // 4-bit operations
 int a[4], b[4], result[4];
 int carry, overflow;

 printf("==================================================\n");
 printf(" BINARY ADDER-SUBTRACTOR DEMONSTRATION (C) \n");
 printf("==================================================\n\n");

 // Test Half Adder
 printf("--- HALF ADDER TRUTH TABLE ---\n");
 printf("A B | Sum Carry\n");
 printf("--------------\n");
 for (int a_val = 0; a_val <= 1; a_val++) {
 for (int b_val = 0; b_val <= 1; b_val++) {
 int s, c;
 half_adder(a_val, b_val, &s, &c);
 printf("%d %d | %d %d\n", a_val, b_val, s, c);
 }
 }

 // Test Full Adder
 printf("\n--- FULL ADDER TRUTH TABLE ---\n");
 printf("A B Cin | Sum Cout\n");
 printf("-----------------\n");
 for (int a_val = 0; a_val <= 1; a_val++) {
 for (int b_val = 0; b_val <= 1; b_val++) {
 for (int cin = 0; cin <= 1; cin++) {
 int s, cout;
 full_adder(a_val, b_val, cin, &s, &cout);
 printf("%d %d %d | %d %d\n", a_val, b_val, cin, s, cout);
 }
 }
 }

 // Test 4-bit Ripple Carry Adder: 5 + 7
 printf("\n--- 4-BIT RIPPLE CARRY ADDER ---\n");
 decimal_to_binary(5, 4, a);
 decimal_to_binary(7, 4, b);
 ripple_carry_adder(a, b, 4, result, &carry);
 printf(" Adding: 5 (0101) + 7 (0111)\n");
 printf(" Binary: ");
 print_binary(result, 4);
 printf("\n");
 printf(" Decimal Result: %d\n", binary_to_decimal(result, 4));
 printf(" Final Carry: %d\n", carry);

 // Test Adder-Subtractor: Addition Mode (6 + 3)
 printf("\n--- ADDER-SUBTRACTOR: ADDITION (Mode=0) ---\n");
 decimal_to_binary(6, 4, a); // 0110
 decimal_to_binary(3, 4, b); // 0011
 adder_subtractor(a, b, 4, 0, result, &overflow);
 printf(" Mode: ADD\n");
 printf(" Adding: 6 (0110) + 3 (0011)\n");
 printf(" Result: ");
 print_binary(result, 4);
 printf(" = %d (decimal)\n", binary_to_decimal(result, 4));
 printf(" Overflow: %d\n", overflow);

 // Test Adder-Subtractor: Subtraction Mode (8 - 3)
 printf("\n--- ADDER-SUBTRACTOR: SUBTRACTION (Mode=1) ---\n");
 decimal_to_binary(8, 4, a); // 1000
 decimal_to_binary(3, 4, b); // 0011
 adder_subtractor(a, b, 4, 1, result, &overflow);
 printf(" Mode: SUBTRACT (uses 2's complement)\n");
 printf(" Computing: 8 (1000) - 3 (0011)\n");
 printf(" = 8 + (-3) = 8 + (1101)\n");
 printf(" Result: ");
 print_binary(result, 4);
 printf(" = %d (decimal)\n", binary_to_decimal(result, 4));
 printf(" Overflow: %d\n", overflow);

 // Test Overflow Detection: 6 + 5 (exceeds 4-bit signed range)
 printf("\n--- OVERFLOW DETECTION ---\n");
 decimal_to_binary(6, 4, a); // 0110 (+6)
 decimal_to_binary(5, 4, b); // 0101 (+5)
 adder_subtractor(a, b, 4, 0, result, &overflow);
 printf(" Adding two positive numbers: +6 + +5\n");
 printf(" Expected: +11, but 4-bit signed range is -8 to +7\n");
 printf(" Result: ");
 print_binary(result, 4);
 printf("\n");
 printf(" Overflow Flag: %d (1 = overflow occurred!)\n", overflow);
 printf(" Actual value in 4-bit signed: %d (WRONG!)\n", 
 binary_to_decimal(result, 4));

 return 0;
}
